export async function generateMetadata({ params }: { params: Promise<{ category: string; id: string }> }): Promise<Metadata> {
  const { category, id } = await params
  const col = COLUMNS[category]?.[Number(id)]
  if (!col) return { title: '記事が見つかりません | やさしい介護ナビ' }
  return {
    title: col.title + ' | やさしい介護ナビ',
    description: col.body.substring(0, 80).replace(/\\n/g, ''),
  }
}

export default async function ColumnPage({ params }: { params: Promise<{ category: string; id: string }> }) {
  const { category, id } = await params
  const col = COLUMNS[category]?.[Number(id)]
  if (!col) notFound()
  const catLabel = CAT_LABEL[category] || ''
  const idNum = Number(id)
  const paragraphs = col.body.split('\\n\\n').filter(Boolean)
  return (
    <main style={{ maxWidth: 480, margin: '0 auto', padding: '16px 16px 48px' }}>
      <div style={{ marginBottom: 16 }}>
        <Link href="/column" style={{ fontSize: 12, color: '#6b7280', textDecoration: 'none' }}>← コラム一覧</Link>
        <p style={{ fontSize: 11, color: '#e05080', fontWeight: 600, margin: '8px 0 4px' }}>{catLabel}</p>
        <h1 style={{ fontSize: 18, fontWeight: 700, color: '#1f2937', lineHeight: 1.5 }}>{col.title}</h1>
      </div>
      <div style={{ background: '#fff', border: '0.5px solid #e5e7eb', borderRadius: 12, padding: '16px', marginBottom: 16 }}>
        {paragraphs.map((p, i) => (
          <p key={i} style={{ fontSize: 14, color: '#374151', lineHeight: 1.8, margin: i < paragraphs.length - 1 ? '0 0 14px' : '0' }}>{p}</p>
        ))}
      </div>
      {col.a8.length > 0 && (
        <div style={{ marginBottom: 16 }}>
          <p style={{ fontSize: 12, color: '#9ca3af', marginBottom: 8 }}>※ 広告・PR</p>
          {col.a8.map((s, i) => (
            <a key={i} href={s.url} target="_blank" rel={s.amazon ? 'noopener noreferrer' : 'nofollow noopener noreferrer'}
              style={{ display: 'block', background: '#fff', border: s.amazon ? '1px solid #FF9900' : '0.5px solid #e5e7eb', borderRadius: 10, padding: '12px 14px', marginBottom: 8, textDecoration: 'none' }}>
              {s.amazon && <div style={{ fontSize: 10, color: '#FF9900', fontWeight: 700, marginBottom: 4 }}>📚 Amazonで見る</div>}
              <div style={{ fontSize: 13, fontWeight: 600, color: '#1f2937', marginBottom: 4 }}>{s.name}</div>
              <div style={{ fontSize: 12, color: '#6b7280', marginBottom: 8 }}>{s.desc}</div>
              <div style={{ background: s.amazon ? '#FF9900' : '#c0305a', color: '#fff', borderRadius: 6, padding: '7px', textAlign: 'center' as const, fontSize: 12, fontWeight: 700 }}>
                {s.amazon ? 'Amazonで見てみる →' : '詳しく見てみる →'}
              </div>
            </a>
          ))}
        </div>
      )}
      <div style={{ display: 'flex', gap: 8, marginBottom: 16 }}>
        {idNum > 1 && <Link href={`/column/${category}/${idNum - 1}`} style={{ flex: 1, display: 'block', textAlign: 'center' as const, background: '#fff', border: '0.5px solid #e5e7eb', borderRadius: 8, padding: '10px', fontSize: 13, color: '#374151', textDecoration: 'none' }}>← 前の記事</Link>}
        {idNum < 10 && <Link href={`/column/${category}/${idNum + 1}`} style={{ flex: 1, display: 'block', textAlign: 'center' as const, background: '#fff', border: '0.5px solid #e5e7eb', borderRadius: 8, padding: '10px', fontSize: 13, color: '#374151', textDecoration: 'none' }}>次の記事 →</Link>}
      </div>
      <Link href="/" style={{ display: 'block', textAlign: 'center' as const, background: '#6b1a30', color: '#fcc0d0', borderRadius: 8, padding: '12px', fontSize: 13, fontWeight: 600, textDecoration: 'none' }}>
        あかりに診断してもらう →
      </Link>
    </main>
  )
}
